/**
 * bookingRepository.js
 *
 * Collection: "bookings"
 * Document ID: auto-generated by Firestore
 *
 * Schema
 * ──────
 * customerId    string      Auth UID of the customer
 * artisanId     string      Auth UID of the artisan
 * serviceType   string      e.g. "Plumbing", "Electrical"
 * status        string      "pending" | "accepted" | "rejected" | "completed" | "cancelled"
 * scheduledAt   string | null   ISO timestamp of the appointment
 * price         number      agreed price in GHC
 * notes         string      any special instructions from the customer
 * address       string      service location
 * createdAt     string      ISO timestamp
 * updatedAt     string      ISO timestamp
 *
 * Required Firestore composite indexes
 * ─────────────────────────────────────
 * 1. customerId ASC + createdAt DESC
 * 2. artisanId  ASC + createdAt DESC
 * 3. customerId ASC + status ASC + createdAt DESC
 * 4. artisanId  ASC + status ASC + createdAt DESC
 */

const DEFAULT_COLLECTION = "bookings";

// All statuses in the canonical booking state machine (snake_case, Firestore authoritative)
const VALID_STATUSES = [
    "pending",       // created, waiting for dispatch
    "dispatching",   // dispatch engine searching
    "searching",     // emergency — scanning for artisan
    "dispatched",    // artisan has been notified, awaiting response
    "assigned",      // artisan assigned via admin or manual flow
    "accepted",      // artisan accepted
    "rejected",      // artisan declined (dispatch re-tries)
    "en_route",      // artisan travelling to customer
    "in_progress",   // job underway
    "awaiting",      // artisan marked done, waiting for customer confirmation
    "completed",     // customer confirmed done / auto-released
    "cancelled",     // cancelled by customer, artisan, or admin
    "unfulfilled",   // dispatch exhausted all artisans — no match found
];

function now() {
    return new Date().toISOString();
}

export function createBookingRepository({
    databaseService,
    collectionName = DEFAULT_COLLECTION
}) {
    if (!databaseService) {
        throw new Error("BookingRepository requires a DatabaseService.");
    }

    return {
        collectionName,

        // ── Read ─────────────────────────────────────────────────────────────

        async getById(bookingId) {
            return databaseService.getDocument(collectionName, bookingId);
        },

        /**
         * All bookings for a customer, newest first.
         * Pass options.status to filter by a specific status.
         */
        async getByCustomerId(customerId, options = {}) {
            const conditions = [{ field: "customerId", op: "==", value: customerId }];
            if (options.status) {
                conditions.push({ field: "status", op: "==", value: options.status });
            }
            return databaseService.queryWithOptions(collectionName, conditions, {
                orderBy: { field: "createdAt", direction: "desc" },
                limit:   options.limit ?? 50
            });
        },

        /**
         * All bookings assigned to an artisan, newest first.
         * Pass options.status to filter by a specific status.
         */
        async getByArtisanId(artisanId, options = {}) {
            const conditions = [{ field: "artisanId", op: "==", value: artisanId }];
            if (options.status) {
                conditions.push({ field: "status", op: "==", value: options.status });
            }
            return databaseService.queryWithOptions(collectionName, conditions, {
                orderBy: { field: "createdAt", direction: "desc" },
                limit:   options.limit ?? 50
            });
        },

        // ── Write ─────────────────────────────────────────────────────────────

        /**
         * Create a new booking. Returns the auto-generated booking ID.
         */
        async create(data) {
            if (!data.customerId) throw new Error("BookingRepository.create: customerId is required.");
            // artisanId is required for standard bookings, but null is allowed for emergency
            // bookings that haven't been matched to an artisan yet.
            if (data.artisanId === undefined) throw new Error("BookingRepository.create: artisanId is required (pass null for emergency bookings).");

            const payload = {
                customerId:  data.customerId,
                artisanId:   data.artisanId ?? null, // null = emergency, unmatched
                serviceType: data.serviceType  ?? "",
                type:        data.type         ?? "standard",
                status:      "pending",
                scheduledAt: data.scheduledAt  ?? null,
                price:       data.price        ?? 0,
                notes:       data.notes        ?? "",
                address:     data.address      ?? "",
                createdAt:   now(),
                updatedAt:   now()
            };

            return databaseService.addDocument(collectionName, payload);
        },

        /**
         * Transition a booking to a new status.
         * Throws if the status value is not in the allowed set.
         */
        async updateStatus(bookingId, status) {
            if (!VALID_STATUSES.includes(status)) {
                throw new Error(`Invalid booking status "${status}". Must be one of: ${VALID_STATUSES.join(", ")}.`);
            }
            await databaseService.updateDocument(collectionName, bookingId, {
                status,
                updatedAt: now()
            });
        },

        /**
         * General-purpose partial update (price, notes, scheduledAt, etc.).
         */
        async update(bookingId, data) {
            const { customerId, artisanId, createdAt, ...safeData } = data;
            await databaseService.updateDocument(collectionName, bookingId, {
                ...safeData,
                updatedAt: now()
            });
        },

        // ── Real-time ─────────────────────────────────────────────────────────

        /**
         * Subscribe to live updates for a customer's bookings from the last 90 days.
         * Older completed bookings are fetched separately via getByCustomerId().
         * Returns an unsubscribe function.
         */
        subscribeByCustomerId(customerId, onChange, onError) {
            const cutoff = new Date();
            cutoff.setDate(cutoff.getDate() - 90);
            return databaseService.subscribeToCollection(
                collectionName,
                [
                    { field: "customerId", op: "==", value: customerId },
                    { field: "createdAt",  op: ">=", value: cutoff.toISOString() },
                ],
                { orderBy: { field: "createdAt", direction: "desc" } },
                onChange,
                onError
            );
        },

        /**
         * Subscribe to live updates for an artisan's bookings from the last 90 days.
         * Older completed bookings are fetched separately via getByArtisanId().
         * Returns an unsubscribe function.
         */
        subscribeByArtisanId(artisanId, onChange, onError) {
            const cutoff = new Date();
            cutoff.setDate(cutoff.getDate() - 90);
            return databaseService.subscribeToCollection(
                collectionName,
                [
                    { field: "artisanId", op: "==", value: artisanId },
                    { field: "createdAt", op: ">=", value: cutoff.toISOString() },
                ],
                { orderBy: { field: "createdAt", direction: "desc" } },
                onChange,
                onError
            );
        }
    };
}
